prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "1f1b01e0a85340689b6df314b32bb4b6" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:id ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "1f1b01e0a85340689b6df314b32bb4b6") ||
         CONTAINS(LCASE(STR(?origId)), "1f1b01e0a85340689b6df314b32bb4b6") ||
         CONTAINS(LCASE(STR(?normId)), "1f1b01e0a85340689b6df314b32bb4b6") ||
         CONTAINS(LCASE(STR(?model)), "1f1b01e0a85340689b6df314b32bb4b6"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?direction WHERE {
  ?gateway a bboExt:ParallelGateway .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  ?gateway tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo <https://www.teamingai-project.eu/kg/model/sid_57deb9e0_f5ba_4380_a35e_0656d288167a> .
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?sourceName ?targetName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-3A28F4F6-52B5-427D-B72F-DE79A1AE4E37> .
  ?edge bbo:has_targetRef ?target .
  OPTIONAL { ?target bbo:name ?targetName . }
  OPTIONAL { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-3A28F4F6-52B5-427D-B72F-DE79A1AE4E37> bbo:name ?sourceName . }
}
